  "result.loading": { en:"Loading results...", hi:"परिणाम लोड हो रहे हैं...", bn:"ফলাফল লোড হচ্ছে...", te:"ఫలితాలు లోడ్ అవుతున్నాయి...", mr:"परिणाम लोड होत आहेत...", ta:"முடிவுகள் ஏற்றப்படுகின்றன...", gu:"પરિણામો લોડ થઈ રહ્યા છે...", kn:"ಫಲಿತಾಂಶಗಳು ಲೋಡ್ ಆಗುತ್ತಿವೆ...", pa:"ਨਤੀਜੇ ਲੋਡ ਹੋ ਰਹੇ ਹਨ...", or:"ଫଳାଫଳ ଲୋଡ ହେଉଛି...", ml:"ഫലങ്ങൾ ലോഡ് ചെയ്യുന്നു..." },
  "error.analysis_failed": { en:"Analysis failed. Please try again.", hi:"विश्लेषण विफल रहा। कृपया पुनः प्रयास करें।", bn:"বিশ্লেষণ ব্যর্থ হয়েছে। আবার চেষ্টা করুন।", te:"విశ్లేషణ విఫలమైంది. దయచేసి మళ్లీ ప్రయత్నించండి.", mr:"विश्लेषण अयशस्वी झाले. कृपया पुन्हा प्रयत्न करा.", ta:"பகுப்பாய்வு தோல்வியடைந்தது. மீண்டும் முயற்சிக்கவும்.", gu:"વિશ્લેષણ નિષ્ફળ થયું. કૃપા કરીને ફરી પ્રયાસ કરો.", kn:"ವಿಶ್ಲೇಷಣೆ ವಿಫಲವಾಗಿದೆ. ದಯವಿಟ್ಟು ಮತ್ತೆ ಪ್ರಯತ್ನಿಸಿ.", pa:"ਵਿਸ਼ਲੇਸ਼ਣ ਅਸਫਲ ਰਿਹਾ। ਕਿਰਪਾ ਕਰਕੇ ਦੁਬਾਰਾ ਕੋਸ਼ਿਸ਼ ਕਰੋ।", or:"ବିଶ୍ଲେଷଣ ବିଫଳ ହୋଇଛି। ଦୟାକରି ପୁଣି ଚେଷ୍ଟା କରନ୍ତୁ।", ml:"വിശകലനം പരാജയപ്പെട്ടു. വീണ്ടും ശ്രമിക്കുക." },
  "feedback.success": { en:"Thank you for your feedback!", hi:"आपकी प्रतिक्रिया के लिए धन्यवाद!", bn:"আপনার মতামতের জন্য ধন্যবাদ!", te:"మీ అభిప్రాయానికి ధన్యవాదాలు!", mr:"तुमच्या अभिप्रायाबद्दल धन्यवाद!", ta:"உங்கள் கருத்துக்கு நன்றி!", gu:"તમારા પ્રતિસાદ માટે આભાર!", kn:"ನಿಮ್ಮ ಪ್ರತಿಕ್ರಿಯೆಗೆ ಧನ್ಯವಾದಗಳು!", pa:"ਤੁਹਾਡੇ ਫੀਡਬੈਕ ਲਈ ਧੰਨਵਾਦ!", or:"ଆପଣଙ୍କ ମତାମତ ପାଇଁ ଧନ୍ୟବାଦ!", ml:"നിങ്ങളുടെ ഫീഡ്ബാക്കിന് നന്ദി!" },
  "upload.take_photo": { en:"Take Photo", hi:"फोटो लें", bn:"ফটো তুলুন", te:"ఫోటో తీయండి", mr:"फोटो घ्या", ta:"புகைப்படம் எடு", gu:"ફોટો લો", kn:"ಫೋಟೋ ತೆಗೆಯಿರಿ", pa:"ਫੋਟੋ ਲਓ", or:"ଫଟୋ ନିଅନ୍ତୁ", ml:"ഫോട്ടോ എടുക്കുക" },
