interface I18nContextType {
  lang: Language;
  setLang: (l: Language) => void;
  t: (key: string) => string;
  translateCrop: (crop: string) => string;
  translateDisease: (disease: string) => string;
}

const I18nContext = createContext<I18nContextType | undefined>(undefined);

export const I18nProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [lang, setLang] = useState<Language>(() => (localStorage.getItem("farmlens_lang") as Language) || "en");

  useEffect(() => {
    localStorage.setItem("farmlens_lang", lang);
  }, [lang]);

  const t = (key: string) => translations[key]?.[lang] ?? translations[key]?.["en"] ?? key;
  
  const translateCrop = (crop: string) => {
    const key = `crop.${crop}`;
    return translations[key]?.[lang] ?? crop;
  };
  
  const translateDisease = (disease: string) => {
    const key = `disease.${disease}`;
    return translations[key]?.[lang] ?? disease;
  };

  return <I18nContext.Provider value={{ lang, setLang, t, translateCrop, translateDisease }}>{children}</I18nContext.Provider>;
};

export const useI18n = () => {
  const ctx = useContext(I18nContext);
  if (!ctx) throw new Error("useI18n must be used within I18nProvider");
  return ctx;
};
